// app/api/files/upload/route.ts
import { NextRequest, NextResponse } from "next/server"
import { writeFile, mkdir } from "fs/promises"
import path from "path"
import { existsSync } from "fs"

export async function POST(req: NextRequest) {
  try {
    const formData = await req.formData()

    const file = formData.get("file") as File
    const fileType = formData.get("fileType") as string
    const workspaceId = formData.get("workspaceId") as string
    const propertyId = formData.get("propertyId") as string
    const uploadedBy = formData.get("uploadedBy") as string
    const description = formData.get("description") as string | null
    const contractorId = formData.get("contractorId") as string | null

    if (!file) {
      return NextResponse.json({ error: "No file provided" }, { status: 400 })
    }

    // Create uploads folder if it doesn't exist
    const uploadDir = path.join(process.cwd(), "public", "uploads", workspaceId)
    if (!existsSync(uploadDir)) {
      await mkdir(uploadDir, { recursive: true })
    }

    // Create unique filename
    const timestamp = Date.now()
    const originalName = file.name.replace(/\s+/g, "-")
    const fileName = `${timestamp}-${originalName}`
    const filePath = path.join(uploadDir, fileName)

    // Save file to disk
    const bytes = await file.arrayBuffer()
    const buffer = Buffer.from(bytes)
    await writeFile(filePath, buffer)

    // Public URL to access the file
    const fileUrl = `/uploads/${workspaceId}/${fileName}`

    // Save metadata to your DB here
    // await FileModel.create({ fileName, fileUrl, fileType, workspaceId, propertyId, uploadedBy, ... })

    return NextResponse.json({
      data: {
        fileName: file.name,
        fileUrl,
        fileType,
        fileSize: file.size,
        workspaceId,
        propertyId,
        uploadedBy,
        description,
        contractorId,
        createdAt: new Date().toISOString(),
      }
    })
  } catch (err) {
    console.error("Upload error:", err)
    return NextResponse.json({ error: "Upload failed" }, { status: 500 })
  }
}